// ─── Registry ────────────────────────────────────────────────────────────

let _renderLib: RenderLib | undefined

export function registerRenderLib(lib: RenderLib): void {
  _renderLib = lib
}

export function resolveRenderLib(): RenderLib {
  if (!_renderLib) {
    throw new Error("No RenderLib registered. In Bun, import '@opentui/core' or '@opentui/core/native' (which loads zig.ts). In browsers, call registerRenderLib() with a browser implementation.")
  }
  return _renderLib
}

export function hasRenderLib(): boolean {
  return _renderLib !== undefined
}

// In Bun, auto-load the native FFI render lib by importing zig.ts.
// The variable path prevents bundlers (esbuild, Vite) from statically
// resolving and including zig.ts in browser bundles.
// In browsers, typeof Bun is undefined so this block is skipped entirely.
if (typeof globalThis.Bun !== "undefined") {
  const zigPath = "./zig"
  try {
    await import(zigPath)
  } catch {
    // Native module not available (e.g. not built yet).
    // resolveRenderLib() will throw a clear error if called.
  }
}

